SELECT t.tour_name, ta.average_cost, ta.cost_variance, ta.total_bookings, ta.revenue, ta.profit
FROM tours t
JOIN tour_analysis ta ON t.tour_id = ta.tour_id;

SELECT AVG(t.high_cost) AS average_high_cost
FROM tours t
WHERE t.high_cost > (
    SELECT AVG(t1.high_cost)
    FROM tours t1
);

SELECT tour_id, MAX(cost) AS highest_cost
FROM tour_pricing
GROUP BY tour_id;

SELECT tour_name, average_rating
FROM tours
ORDER BY average_rating DESC;

SELECT COUNT(*) 
FROM bookings 
WHERE tour_id = (SELECT tour_id FROM tours WHERE tour_name = 'Tour 1');

SELECT category_id, COUNT(*) AS number_of_tours
FROM tour_pricing
GROUP BY category_id;
